var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"무인지대 상공 3500m","JPN":"無人地帯上空3500m","ENG":"3500 m above No-man's land","TWN":"無人區上空3500m"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"함선 페가수스, <color=#ffd34c>낚싯대</color> 운송 작전 이행 중-","JPN":"艦船ペガサス、<color=#ffd34c>釣り竿</color>輸送作戦遂行中","ENG":"Pegasus, In transport to deliver the <color=#ffd34c>Fishing Rod</color>.","TWN":"天馬艦船，正在執行<color=#ffd34c>釣魚竿</color>運輸任務。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"P37, 북방합의체 영공으로 진입한다.","JPN":"P37、北方合意体の領空へ進入する。","ENG":"P37, Entering Northern Union airspace.","TWN":"P37，即將進入北方和議會領空。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"목적지 도착까지 예상 비행 시간은 50분. 화물 투하를 위해 30분 뒤 고도를 300m까지 낮출 예정이다.","JPN":"目的地到着までの飛行予想時間は50分。貨物投下のため、30分後高度を300mまで下げる予定。","ENG":"Estimated flight time until the destination is 50 minutes. Will lower altitude to 300 m in 30 minutes to drop the cargo.","TWN":"預計50分鐘後到達目標地點。為投放貨物，30分鐘後將降低飛行高度至300m。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"발각되지 않도록 우회 경로를 설정 중입니다.","JPN":"見つからないように迂回ルートを設定中です。","ENG":"Setting up a detour route to avoid detection.","TWN":"正在設置繞行路線以避免被發現。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L8_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"북방합의체 놈들, 방공망이 아주 촘촘하군요. 세계대전이라도 준비한답니까?","JPN":"北方合意体のやつら、なかなかの防空網ですね。世界大戦でも準備しているのでしょうか？","ENG":"Those Northern Union bastards. Their air defense network is too tight. Are they preparing for a world war or something?","TWN":"北方和議會的混蛋，防空網真是密不透風啊。他們是在準備世界大戰嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"비행형 침식체를 막기 위해서라더군. 적어도 공식 입장은 그래.","JPN":"飛行型侵食体を防ぐためらしい。公式的な理由はな。","ENG":"They say it's to prevent flying C.O.s. Or at least that's their official statement.","TWN":"為了阻止飛行侵蝕體。至少官方說法是這樣。"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"흥, 신호 방해기로 위성 관측을 막은 것도 침식체 때문이라고 둘러대던가요?","JPN":"ふん。ジャミングで衛星の観測を邪魔したのも侵食体のせいって言うでしょうね。","ENG":"Hmph. Did they also say they blocked the satellite observation with a signal jammer because of the C.O.s too?","TWN":"哼，那麼他們用訊號干擾器阻止衛星觀測該怎麼解釋？"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_FIRE_SMALL"},{"id":"L17_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"윽?!","JPN":"うっ！？","ENG":"Ngh?!","TWN":"呃？！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"북방합의체 측 전투기 편대입니다! 추적 당하고 있어요!","JPN":"北方合意体側戦闘機の編隊です！　追跡されています！","ENG":"The Northern Union's fighter jet squadron! We're being tailed!","TWN":"北方和議會的戰鬥機編隊！我們被追蹤了！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"엔진에는 타격이 없어. 이대로 목적지까지 간다.","JPN":"エンジンにダメージはない。このまま目的地まで行くぞ。","ENG":"There's no damage to the engine. We keep course to our destination.","TWN":"引擎沒有受損。就這樣前往目的地。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"추격이 너무 빠릅니다! 도착까지 못 버텨요!","JPN":"追撃が速すぎます！　到着まで持ちません！","ENG":"They're gaining on us! We won't make it at this rate!","TWN":"追擊太快了！撐不到那裡！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"시니어님 말씀 기억하지? 그 곰인형에 달린 스위치를 켜!","JPN":"シニアの言葉を覚えているか？　そのクマのぬいぐるみのスイッチを押すんだ！","ENG":"Do you remember what the Senior said to us? Flip the switch on the teddy bear!","TWN":"記得Senior的話嗎？打開那隻玩具熊上的開關！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"진심이십니까? 당연히 농담하는 건 줄 알았는데요?","JPN":"え？　あれは冗談じゃなかったんですか？","ENG":"Are you serious? I thought that was just a joke!","TWN":"你是認真的嗎？我還以為那是在開玩笑呢！？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"어떻게든 되겠지! 이대로 아티팩트를 빼앗기고 싶은 거냐?","JPN":"なんとかなるだろ！　このままアーティファクトを奪われてもいいのか！","ENG":"We have to do something! I'm not letting them take the Artifact!","TWN":"必須做點什麼！你想就這樣被搶走人造神器嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"켰습니다…!","JPN":"押しました……！","ENG":"It's on...!","TWN":"開了……！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"하지만 아무 반응도 없는…","JPN":"しかし、何の反応も……","ENG":"But nothing's happen–","TWN":"但沒有任何反應……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"치, 침식파 밀도 급상승!","JPN":"し、侵食波密度、急上昇！","ENG":"C-Corruption ray levels are spiking!","TWN":"侵、侵蝕波密度急速上升！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"뭔가 옵니다! 식별 신호 확인 중…!","JPN":"何かが来ます！　識別信号を確認中……！","ENG":"Something's coming! Checking the identification signal...!","TWN":"有東西來了！正在確認識別訊號……！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"…데모고르곤?","JPN":"……デモゴルゴン？","ENG":"...A Demogorgon?","TWN":"是……是魔神？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ARTIL_ADMIN_QM_NULL","text":{"KOREA":"좌표를 송신 받았다.","JPN":"座標を受信した。","ENG":"The coordinates were sent.","TWN":"已接收到座標。"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"비상 상황. 관리국 수송선을 추격 중이던 165 기동 편대가 일제히 무동력 상태로 전환됐다.","JPN":"非常事態。管理局の輸送船を追撃していた165機動編隊が一斉に無動力状態に切り替えられた。","ENG":"Alert. The 165th squadron chasing the Administration's transportation ship have all lost power.","TWN":"緊急情況。追擊管理局運輸船的165機動編隊突然全部失去動力。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AIRCRAFT_STATE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"방해전파는 감지되지 않았어. 관리국이 무슨 수작을 부린 건가?","JPN":"妨害電波は感知されていない。管理局が何かしたのか？","ENG":"No jammers were detected. What kind of trick did the Administration pull?","TWN":"沒有檢測到干擾訊號。管理局在搞什麼鬼？"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"AIRCRAFT_STATE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_21"},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"고위 침식 반응이다! 침식파가 시스템을 교란하고 있어!","JPN":"高レベルの侵食反応だ！　侵食波がシステムを撹乱している！","ENG":"High Corruption detected! The Corruption ray is messing with the system!","TWN":"檢測到高侵蝕反應！是侵蝕波干擾了系統！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AIRCRAFT_STATE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"통제권을 완전히 빼앗겼다! 탈출해!","JPN":"統制権を完全に奪われた！　脱出しろ！","ENG":"Mayday, mayday! We've completely lost control! Eject!","TWN":"完全失去控制權！準備彈射！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"보셨습니까?","JPN":"見ましたか？","ENG":"Did you see that?","TWN":"你看到了嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"저흴 추격해오던 전투기들이 추락하고 있어요.","JPN":"私たちを追っていた戦闘機がすべて墜落しています。","ENG":"All the fighter jets that were chasing us started crashing to the ground.","TWN":"追擊我們的戰鬥機掉下去了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COPILOT_VOICE_ADMIN_NULL","text":{"KOREA":"게다가 방금 전까지의 침식 반응은 거짓말처럼 사라졌고요.","JPN":"先程までの侵食反応は嘘のように消えました。","ENG":"And the Corruption response from before vanished like it wasn't even there from the start.","TWN":"而且剛才的侵蝕反應也像沒發生過一樣消失了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COPILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"그래. 보고도 믿기지 않는군.","JPN":"ああ……この目で見たのに、まだ信じられないな。","ENG":"Yes. I can't believe it, even after seeing what happened.","TWN":"雖然親眼見到了，但還是難以置信……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PILOT_VOICE_ADMIN_NULL","text":{"KOREA":"설마 이 곰인형도… 우리가 모르는 아티팩트인 건가?","JPN":"まさか、このぬいぐるみも……私たちの知らないアーティファクトなのだろうか？","ENG":"Is this teddy bear... an Artifact that we're unaware about?","TWN":"難道這個玩具熊……也是我們不知道的人造神器嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PILOT_VOICE_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINISTER_UNION_NPC_NULL","text":{"KOREA":"펠릭스. 잠시 얘기 괜찮나?","JPN":"フェリックス、少しいいか？","ENG":"Felix. Could we talk for a minute?","TWN":"緋莉克絲。我想和你談談，有時間嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"네, 듣고 있습니다. 장관님.","JPN":"はい。聞こえています、長官。","ENG":"Yes, you have my attention, Minister.","TWN":"是，我能聽到，長官。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINISTER_UNION_NPC_NULL","text":{"KOREA":"관리국의 페가수스가 우리 추적을 따돌리고 사라졌어. 자네가 나서줘야겠네.","JPN":"管理局のペガサスが我々の追跡をかわして姿を消した。君に出てもらいたい。","ENG":"The Administration's Pegasus that we were in pursuit of has vanished. I think you should handle this.","TWN":"管理局的天馬甩開了我們的追蹤消失了。得你出馬了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"장관님께선 관리국과의 직접적인 충돌은 피하고 싶어하는 줄 알았는데요?","JPN":"長官は管理局との直接的な衝突は避けたいほうだと思っていましたが。","ENG":"I thought you wanted to avoid any direct confrontation with the Administration, sir?","TWN":"喔？我以為部長不想與管理局發生直接衝突呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MINISTER_UNION_NPC_NULL","text":{"KOREA":"마음에도 없는 소리 말자고.","JPN":"心にもないことを言うのはやめてくれ。","ENG":"We both know you don't mean that.","TWN":"別說違心之論。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L19_1","type":"dialog","speaker":"MINISTER_UNION_NPC_NULL","text":{"KOREA":"놈들이 아티팩트를 싣고 있단 정보를 사령부에 흘린 게 자네란 걸 내가 모를 줄 아나?","JPN":"やつらがアーティファクトを運んでいるという情報を司令部に流したのは君だろう。私が知らないとでも思ったのか？","ENG":"Did you think I wouldn't know that it was you who leaked intel to Command about them carrying an Artifact?","TWN":"你以為我不知道是你把他們運送人造神器的消息洩露給司令部的嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"근신 중인 제가 감히 장관님을 직접 만나 뵐 순 없으니까요.","JPN":"謹慎処分を受けている私が長官に直接お会いすることはできませんから。","ENG":"I couldn't dare to ask to meet you since I am currently on probation, sir.","TWN":"因為我正在接受檢查，怎麼敢直接去見部長呢？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"하지만 상대는 관리국입니다. 어떤 목적으로 이곳에 왔건, 아티팩트를 쉽게 내어주진 않을 거예요.","JPN":"しかし相手は管理局です。ここに来た理由が何であれ、そう簡単にはアーティファクトを渡してはくれないでしょう。","ENG":"But it's the Administration. Whatever their reason for coming here, they won't give up the Artifact that easily.","TWN":"而且對方是管理局。不管他們出於什麼目的來到這裡，都不會輕易交出人造神器吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MINISTER_UNION_NPC_NULL","text":{"KOREA":"핵심만 묻지. 자네가 나서면 그 아티팩트를 입수할 수 있겠나?","JPN":"単刀直入に聞く。君ならそのアーティファクトを入手できるか？","ENG":"Let's cut to the chase. Can you retrieve the Artifact?","TWN":"我只問重點。你出手的話，能拿到那件神器嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"장관님의 지시라면 해내야죠.","JPN":"それが長官の指示なら、やり遂げてみせます。","ENG":"If that is your order, then I must.","TWN":"如果是部長的指示，我一定會完成。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINISTER_UNION_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MINISTER_UNION_NPC_NULL","text":{"KOREA":"징계 처분은 철회하지. 서둘러 복귀하게.","JPN":"懲戒処分は撤回しよう。急いで復帰するように。","ENG":"Then your probation has been withdrawn. Get back on duty.","TWN":"你的處分已經撤銷了，趕快回來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MINISTER_UNION_NPC_NULL","text":{"KOREA":"수단 방법은 가릴 필요 없네. 아티팩트 입수를 최우선으로 하도록.","JPN":"手段は選ぶな。何があってもアーティファクトの入手が最優先だ。","ENG":"Take any measures necessary. Your utmost priority is to obtain the Artifact.","TWN":"無論用什麼手段，以獲取神器為最優先。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"알겠습니다, 장관님.","JPN":"了解しました、長官。","ENG":"Understood, sir.","TWN":"明白，長官。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"예정대로네요. 이제 대기 중인 부대원들을 소집하겠습니다.","JPN":"予定どおりですね。待機中の部隊員に召集をかけます。","ENG":"Just as planned. I will gather our troops on standby.","TWN":"一切和計畫的一樣。我現在就召集待命的部隊成員。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그래. 남은 차만 마저 비우고 출발하자.","JPN":"そうだな。このお茶を飲み終わったら出発しよう。","ENG":"Yes. But let me finish my cup of tea before we depart.","TWN":"很好，喝完剩下的茶就出發吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"인질은 어떻게 할까요?","JPN":"人質はどうしましょうか？","ENG":"What about the hostage?","TWN":"人質那邊要怎麼辦？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"넌 지금부터 G동 격리소를 지키도록 해.","JPN":"君はいまからＧ棟の隔離所を守れ。","ENG":"You will be guarding the quarantine center in G Wing from now on.","TWN":"你從現在開始負責防守G棟的隔離區。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"관리국이나 다른 방해꾼이 <color=#ffd34c>인질</color>을 빼돌리지 못하게 하는 거야.","JPN":"管理局や他の邪魔者が<color=#ffd34c>人質</color>を助け出せないように。","ENG":"It's your responsibility to prevent the Administration or other intruders from taking the <color=#ffd34c>hostage</color>.","TWN":"你的任務是防止管理局或其他妨礙者把<color=#ffd34c>人質</color>帶走。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그리고… 내가 신호를 보내면, 그걸로 인질의 심장을 찌르면 돼.","JPN":"そして……私が合図を出したら、それで人質の心臓を刺すのだ。","ENG":"Also... when I give you the signal, you can stab the hostage's heart with this.","TWN":"然後……當我發出訊號時，用這個刺穿人質的心臟就行了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINISTER_UNION_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"이건… 검조각?","JPN":"これは……剣の欠片ですか？","ENG":"This is... a sword fragment?","TWN":"這是……一塊劍的碎片？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그건 우리가 이면세계에서 입수한 <color=#ffd34c>늑대 이빨</color>이란 거야.","JPN":"それは私たちが裏世界で入手した<color=#ffd34c>オオカミの牙</color>というものだ。","ENG":"These are the <color=#ffd34c>Wolf's Fang</color> we got from the Counterside.","TWN":"那是我們在異界獲得的<color=#ffd34c>狼牙</color>。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그 인질은 평범한 인간이 아니라서, 보통 물건으로는 죽지 않거든.","JPN":"あの人質は普通の人間じゃないせいで、普通の武器では殺せなくてな。","ENG":"That hostage is no ordinary human, so no normal object would be able to kill her.","TWN":"那個人質不是普通人，用一般的東西是殺不死她的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"외람되지만, 왜 기껏 생포한 인질을 처분하시려는 건지…","JPN":"恐れ入りますが、せっかく生け捕りにした人質を始末する理由は……","ENG":"It's presumptuous, but why are you disposing of the hostage when we captured her alive...?","TWN":"冒昧問一句，為什麼要殺掉好不容易活捉的人質……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"너도 봤잖아?","JPN":"君も見ただろう？","ENG":"Didn't you see it as well?","TWN":"你不是也看到了嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그 여자에겐 운명이 없다는 거 말이야.","JPN":"あの女には運命がない。","ENG":"That woman has no fate.","TWN":"那個女人沒有命運。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"죽음은 운명이란 양피지 위에서만 쓰여지는 거야.","JPN":"死とは運命という名の羊皮紙の上に書かれるもの。","ENG":"Death is written only on the parchment of fate.","TWN":"死亡只會寫在命運的羊皮紙上。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그러니 우선 그녀의 운명을 이곳으로 불러들여야지.","JPN":"まずは彼女の運命をこっちへ呼び込むほうが先だ。","ENG":"So, we must summon her fate here first.","TWN":"所以首先要把她的命運召喚到這裡來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…그렇군요.","JPN":"……そういうことでしたか。","ENG":"...I see.","TWN":"……我明白了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그 꼬리 달린 꼬마가 우물로 들어가게 내버려두신 건… 그런 이유였네요.","JPN":"あの尻尾の生えたチビを井戸に入らせたのは……そういう理由だったのですね。","ENG":"So letting that tailed one fall into the Well was... for that exact reason.","TWN":"你放那個帶尾巴的小傢伙進井裡……原來是這個原因啊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"지금쯤 관리국은 우물에서 그녀의 운명을 찾고 있을 거야.","JPN":"今頃管理局は井戸で彼女の運命を探しているだろう。","ENG":"About now, the Administration should be searching for her fate within the Well.","TWN":"現在管理局應該正在井裡尋找她的命運。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"하지만 그 육체를 우리가 가지고 있으니, 그들이 운명을 되찾더라도 잠시나마 그 둘은 떨어져 있을 수 밖에 없지.","JPN":"だがその肉体は私たちの手にある。彼らがもし運命を取り返すことができたとしても、しばらく2人は離れていることになる。","ENG":"But since we have her physical body, even if they retrieve her fate, it will have to stay separated for a while.","TWN":"但因為我們囚禁了那具肉身，即使他們找回了命運，這兩者也會處於暫時分開的狀態。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"육체와 운명이 한 세계에 존재하지만, 물리적으로는 분리되어 있는 상황.","JPN":"肉体と運命が同じ世界に存在するものの、物理的に分離されている状況……","ENG":"When her body and fate exist in the same world, but are physically separated.","TWN":"肉身和命運存在於同一個世界，但在物理上是分離的時候……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그때가 그 여자의 목숨이 가장 취약한 타이밍이 될 거야.","JPN":"あの女の命が隙だらけになるタイミングだ。","ENG":"That is when she will be at her weakest.","TWN":"那便是那個女人最為脆弱的時刻。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그때… 제가 이 검조각으로 인질을 처리하는 거군요.","JPN":"そのタイミングに……私がこの欠片で人質を始末するということですね。","ENG":"That will be... when I use this sword fragment to get rid of the hostage.","TWN":"那時候……我就用這把劍的碎片處理掉她。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"할 수 있겠지?","JPN":"できるな？","ENG":"Can I count on you?","TWN":"能做到吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"네…","JPN":"はい……","ENG":"Of course...","TWN":"是……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"명령대로 하겠습니다!","JPN":"成功させてみせます！","ENG":"I shall do as you command.","TWN":"遵命！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"R":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};